function cekStok(jumlah) {
  return new Promise(function(resolve, reject) {
    if (jumlah > 0) {
      resolve('Stok tersedia: ' + jumlah + ' item');
    } else {
      reject('Stok habis');
    }
  });
}

cekStok(5)
  .then(function(pesan) {
    console.log(pesan);
  })
  .catch(function(error) {
    console.log(error);
  });
